SELECT metric_type_id, MIN(threshold_value) AS min_threshold_value
FROM metric_thresholds
GROUP BY metric_type_id;

SELECT resolved, COUNT(*) AS violation_count
FROM metric_violations
GROUP BY resolved;

SELECT COUNT(*) 
FROM metric_violations 
WHERE resolved = 0;

SELECT violation_description
FROM metric_violations
WHERE resolved = 1;

SELECT MAX(metric_value) AS peak_nom_value
FROM metrics
WHERE metric_type_id = (SELECT metric_type_id FROM metric_types WHERE metric_type_name = 'NOM');

SELECT COUNT(*) AS project_count
FROM metric_history
WHERE metric_id = 1 AND metric_value > 10;

SELECT MAX(threshold_value) AS max_threshold_value
FROM metric_thresholds
WHERE metric_type_id = 1;

SELECT module_id, metric_value
FROM metrics
WHERE metric_type_id = (SELECT metric_type_id FROM metric_types WHERE metric_type_name = 'NOF');
